def find_first_greater(arr, target):
    left, right = 0, len(arr) - 1
    while left <= right:
        mid = left + (right - left) // 2
        if arr[mid] <= target:
            left = mid + 1
        else:
            right = mid - 1
    return left if left < len(arr) and arr[left] > target else -1

def merge_intervals(intervals):
    if not intervals:
        return []

    merged = [intervals[0]]
    for current in intervals[1:]:
        last = merged[-1]
        if last[1] >= current[0]:
            last[1] = max(last[1], current[1])
        else:
            merged.append(current)
    return merged

class LRUCache:
    def __init__(self, capacity: int):
        self.capacity = capacity
        self.cache = {}
        self.order = []

    def get(self, key: int) -> int:
        if key in self.cache:
            self.order.remove(key)
            self.order.append(key)
            return self.cache[key]
        return -1

    def put(self, key: int, value: int) -> None:
        if key in self.cache:
            self.order.remove(key)
        elif len(self.cache) == self.capacity:
            oldest_key = self.order.pop(0)
            del self.cache[oldest_key]
        self.cache[key] = value
        self.order.append(key)

def is_valid_parentheses(s):
    stack = []
    mapping = {')': '(', ']': '[', '}': '{'}
    for char in s:
        if char in mapping.values():
            stack.append(char)
        elif char in mapping.keys():
            if not stack or mapping[char] != stack.pop():
                return False
    return not stack

def compress_string(s):
    if not s:
        return ""

    compressed = []
    count = 1
    for i in range(1, len(s)):
        if s[i] == s[i-1]:
            count += 1
        else:
            compressed.append(s[i-1] + str(count))
            count = 1
    compressed.append(s[-1] + str(count))

    return ''.join(compressed) if len(''.join(compressed)) < len(s) else s

def rotate_matrix(matrix):
    n = len(matrix)
    for i in range(n // 2):
        for j in range(i, n - i):
            temp = matrix[i][j]
            matrix[i][j] = matrix[n - j - 1][i]
            matrix[n - j - 1][i] = matrix[n - i - 1][n - j - 1]
            matrix[n - i - 1][n - j - 1] = matrix[j][n - i - 1]
            matrix[j][n - i - 1] = temp

def min_window(s, t):
    from collections import Counter

    if not s or not t:
        return ""

    t_count = Counter(t)
    left, right = 0, 0
    valid = 0
    start, length = 0, float('inf')

    while right < len(s):
        c = s[right]
        right += 1
        if c in t_count and t_count[c] > 0:
            t_count[c] -= 1
            if t_count[c] >= 0:
                valid += 1

        while valid == len(t):
            if right - left < length:
                start, length = left, right - left

            d = s[left]
            left += 1
            if d in t_count and t_count[d] >= 0:
                t_count[d] += 1
                if t_count[d] == 0:
                    valid -= 1

    return "" if length == float('inf') else s[start:start + length]

def flatten(nested):
    flat_list = []
    for item in nested:
        flat_list.extend(flatten(item) if isinstance(item, list) else [item])
    return flat_list

def length_of_longest_substring(s):
    start = 0
    max_len = 0
    seen = {}
    for end in range(len(s)):
        if s[end] in seen and start <= seen[s[end]]:
            start = seen[s[end]] + 1
        else:
            max_len = max(max_len, end - start + 1)
        seen[s[end]] = end
    return max_len
